command.text:
&CreateTicket;
declare @message nvarchar(4000), @$lockedDate nvarchar(512) select @$lockedDate = case when @@language = 'v' then N'Đã khóa số liệu, kiểm tra lại ngày khóa sổ.' else N'Data is locked, you must modify system locked date.' end select @message = 'this._authorize = ' + rtrim(@@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@@admin, @@userID, '&TransferID;', 'New')) + ';this._key = ''' + @ticket + ''';load$Grid(this);'
if exists(select 1 from dmstt where year(ngay_ks) >= nam_bd) begin select 'this._denyNew = true;this._denyEdit = true;this._denyDelete = true;this._denyMessage=''' + @$lockedDate + ''';' + @message as message return end if exists(select 1 from dmdvcsks where ma_dvcs = @@unit and year(ngay_ks) >= (select nam_bd from dmstt)) begin select 'this._denyNew = true;this._denyEdit = true;this._denyDelete = true;this._denyMessage=''' + @$lockedDate + ''';' + @message as message return end if @@admin <> 1 begin if not exists(select 1 from sysunitrights where user_id = @@userID and ma_dvcs = @@unit and r_new = 1) begin select 'this._denyNew = true;' + @message as message return end end select @message as message return

script.text:

function load$Grid(g) {
  g.add_onResponseComplete(on$Grid&TransferID;$ResponseComplete);  
  g.add_commandEvent(on$Grid&TransferID;$ExecuteCommand);
}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$Grid&TransferID;$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$Grid&TransferID;$ResponseComplete);} catch (ex) {}  
}
function on$Grid&TransferID;$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'JobAccumulationBalanceImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$Grid&TransferID;$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function show$Form(g, c) {
  (g._authorize == 1) && (!g._denyNew) ? g.showForm(c) : $message.show(g._denyMessage ? g._denyMessage : $df.getResources(g._language, "Message.NotAccess"));
}

      &DowloadScript;
